      {"id": "statusField", "name": "Status Field", "type": "variable", "desc": "Status/type field.", "example": "ActivityType"},
      {"id": "titleText", "name": "Title Text", "type": "string", "desc": "Panel title.", "example": "Activity Timeline"},
